import{_ as t,o as r,c as a,a0 as o}from"./chunks/framework.jwovEGr5.js";const w=JSON.parse('{"title":"Review Import Rows","description":"","frontmatter":{},"headers":[],"relativePath":"imports/review-rows.md","filePath":"imports/review-rows.md"}'),i={name:"imports/review-rows.md"};function l(d,e,s,n,c,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="review-import-rows" tabindex="-1">Review Import Rows <a class="header-anchor" href="#review-import-rows" aria-label="Permalink to &quot;Review Import Rows&quot;">​</a></h1><p>The review page is where raw detected rows become trustworthy rows.</p><blockquote><p>Screenshot placeholder: import-review-before.png Screenshot placeholder: import-review-after.png Screenshot placeholder: import-row-edit.png</p></blockquote><h2 id="what-you-can-do-here" tabindex="-1">What you can do here <a class="header-anchor" href="#what-you-can-do-here" aria-label="Permalink to &quot;What you can do here&quot;">​</a></h2><p>From the review table, you can:</p><ul><li>filter rows</li><li>accept one row</li><li>accept all rows needing attention</li><li>edit a row</li><li>rematch a row against current players</li><li>ignore a row</li><li>restore an ignored row</li><li>add a new preview row manually</li></ul><h2 id="the-four-review-filters" tabindex="-1">The four review filters <a class="header-anchor" href="#the-four-review-filters" aria-label="Permalink to &quot;The four review filters&quot;">​</a></h2><p>The row filters are:</p><ul><li><strong>All</strong></li><li><strong>Needs review</strong></li><li><strong>Saved</strong></li><li><strong>Ignored</strong></li></ul><p>These help you focus on the rows that still need work.</p><h2 id="the-ten-review-row-statuses" tabindex="-1">The ten review-row statuses <a class="header-anchor" href="#the-ten-review-row-statuses" aria-label="Permalink to &quot;The ten review-row statuses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Row status</th><th>What it means</th></tr></thead><tbody><tr><td><code>ready</code></td><td>A clean row waiting for accept.</td></tr><tr><td><code>needs_review</code></td><td>The app found something uncertain.</td></tr><tr><td><code>unmatched_player</code></td><td>No current player match was found.</td></tr><tr><td><code>low_confidence</code></td><td>OCR was unsure about the row.</td></tr><tr><td><code>duplicate</code></td><td>The same player appears more than once in the import.</td></tr><tr><td><code>conflict</code></td><td>A saved result already exists and accepting will overwrite it.</td></tr><tr><td><code>ignored</code></td><td>You set the row aside on purpose.</td></tr><tr><td><code>accepted</code></td><td>The row was accepted and saved against an existing player.</td></tr><tr><td><code>created</code></td><td>The row was accepted and a new player was created for it.</td></tr><tr><td><code>saved</code></td><td>The row is persisted through another save path.</td></tr></tbody></table><h2 id="what-to-check-before-accepting" tabindex="-1">What to check before accepting <a class="header-anchor" href="#what-to-check-before-accepting" aria-label="Permalink to &quot;What to check before accepting&quot;">​</a></h2><p>Review:</p><ul><li>player name</li><li>score or power</li><li>match target</li><li>confidence</li><li>warnings</li><li>status</li></ul><p>If a row looks wrong, edit it first. If it should not be used, ignore it.</p><h2 id="special-warnings" tabindex="-1">Special warnings <a class="header-anchor" href="#special-warnings" aria-label="Permalink to &quot;Special warnings&quot;">​</a></h2><ul><li><strong>Conflict</strong> means accepting will overwrite an existing result.</li><li><strong>Duplicate</strong> means you should check whether one row is the accidental extra.</li><li><strong>Unmatched</strong> may mean the player is missing, renamed, or simply read badly.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./apply-import.html">Accept Rows (Apply an Import)</a></li><li><a href="./import-mistakes.html">Fixing Import Mistakes</a></li></ul>',20)])])}const u=t(i,[["render",l]]);export{w as __pageData,u as default};
